"use client";

/**
 * Cutting Audit queue — single list, unlock-flag based.
 *
 * Migration 032 retired the second "Sent back for edit" section.
 * Every block in the audit queue sits at status='awaiting_approval'.
 * What changes per-row is `cutterEditUnlocked` — when true, the
 * cutter (team_head submitter) gets an Edit button. When false,
 * only the auditor can edit / approve.
 *
 * Buttons by role × unlock state
 *   Auditor + locked   → [✓ Approve] [✏ Edit] [🔓 Allow cutter to edit]
 *   Auditor + unlocked → [✓ Approve] [✏ Edit] [🔒 Lock cutter edit]
 *                        + small "🔓 Cutter can edit · note" indicator
 *   Cutter + locked    → read-only ("Waiting for auditor review")
 *   Cutter + unlocked  → [✏ Edit submission] · "Auditor unlocked editing"
 *                        + sent-back-note prominently
 *
 * Edit doesn't open a modal — it navigates to /cutting/[id]?edit=approval
 * which renders the pre-filled FinishBlockForm.
 */

import Link from "next/link";
import { useState, useTransition } from "react";
import { useRouter } from "next/navigation";

export type ApprovalRow = {
  id: string;
  blockId: string;
  sessionCode: string | null;
  stone: string | null;
  yard: number | null;
  /** Mig 126 — slabs of this block released early as PRE-CUT before the
   *  final submission. >0 colours the card so the auditor knows. */
  precutCount?: number;
  cutterEditUnlocked: boolean;
  submittedAt: string | null;
  submittedByName: string | null;
  operatorName: string | null;
  unlockAt: string | null;
  unlockByName: string | null;
  unlockNote: string | null;
  editedAt: string | null;
  editedByName: string | null;
  payloadSummary: {
    cutCount: number;
    notCutCount: number;
    extraCount: number;
    transferCount: number;
    remainderCount: number;
    stockLocation: string | null;
    restock: boolean;
  } | null;
  isOwnSubmission: boolean;
  /** Projected recovery from the submitted payload (block vs cut slabs +
   *  remainders). Shown as a green / yellow / red bar before approval. */
  recovery: { slabPct: number; restockPct: number; wastePct: number } | null;
};

type ServerResult = { ok: true } | { ok: false; error: string };

export function ApprovalsClient({
  canApprove,
  canEditUnlockedAsCutter = false,
  rows,
  approveAction,
  unlockAction,
  lockAction,
}: {
  canApprove: boolean;
  /** True for team_head / senior_incharge / cutting_operator — they may
   *  edit an unlocked block even if they didn't submit it (shift handoff). */
  canEditUnlockedAsCutter?: boolean;
  rows: ApprovalRow[];
  approveAction: (formData: FormData) => Promise<ServerResult>;
  unlockAction: (formData: FormData) => Promise<ServerResult>;
  lockAction: (formData: FormData) => Promise<ServerResult>;
}) {
  return (
    <div style={{ marginTop: 18 }}>
      <div
        style={{
          display: "flex",
          alignItems: "baseline",
          gap: 8,
          marginBottom: 10,
          paddingBottom: 6,
          borderBottom: "1px solid var(--border)",
        }}
      >
        <h2 style={{ margin: 0, fontSize: 16, fontWeight: 700, color: "var(--text)" }}>
          👀 Awaiting audit
        </h2>
        <span className="muted" style={{ fontSize: 12 }}>
          {rows.length} block{rows.length === 1 ? "" : "s"}
        </span>
        {rows.some((r) => r.cutterEditUnlocked) && (
          <span style={{ fontSize: 11, color: "var(--muted)" }}>
            ·{" "}
            <span style={{ color: "#15803d", fontWeight: 600 }}>
              {rows.filter((r) => r.cutterEditUnlocked).length} unlocked
            </span>
            {" "}for cutter edit
          </span>
        )}
      </div>

      {rows.length === 0 ? (
        <div
          className="muted"
          style={{
            fontSize: 12,
            padding: "10px 14px",
            background: "var(--surface)",
            border: "1px dashed var(--border)",
            borderRadius: 6,
          }}
        >
          {canApprove
            ? "Nothing waiting for audit right now."
            : "You don't have any Cutting Done submissions waiting for audit."}
        </div>
      ) : (
        <div style={{ display: "flex", flexDirection: "column", gap: 10 }}>
          {rows.map((row) => (
            <ApprovalCard
              key={row.id}
              row={row}
              canApprove={canApprove}
              canEditUnlockedAsCutter={canEditUnlockedAsCutter}
              approveAction={approveAction}
              unlockAction={unlockAction}
              lockAction={lockAction}
            />
          ))}
        </div>
      )}
    </div>
  );
}

function ApprovalCard({
  row,
  canApprove,
  canEditUnlockedAsCutter,
  approveAction,
  unlockAction,
  lockAction,
}: {
  row: ApprovalRow;
  canApprove: boolean;
  canEditUnlockedAsCutter: boolean;
  approveAction: (formData: FormData) => Promise<ServerResult>;
  unlockAction: (formData: FormData) => Promise<ServerResult>;
  lockAction: (formData: FormData) => Promise<ServerResult>;
}) {
  const router = useRouter();
  const [pending, startTransition] = useTransition();
  const [actionError, setActionError] = useState<string | null>(null);
  const [showUnlock, setShowUnlock] = useState(false);
  const [unlockNote, setUnlockNote] = useState("");

  const summary = row.payloadSummary;
  const unlocked = row.cutterEditUnlocked;

  // Cutters edit only when unlocked. Approvers edit any time. A
  // cutter-role user (team_head / senior_incharge / cutting_operator)
  // can pick up an unlocked block even if a colleague submitted it —
  // shift handoff, same rule the edit action enforces. Previously this
  // required isOwnSubmission, so a team_head who didn't personally
  // submit the block saw no Edit button after the auditor unlocked it.
  const cutterCanEdit =
    !canApprove && unlocked && (row.isOwnSubmission || canEditUnlockedAsCutter);

  function runApprove() {
    // Daksh (May 2026) — guard against the wrong click. An auditor
    // approving a block locks the cut in production: slabs commit,
    // remainder blocks generate, the donor block flips to consumed.
    // Reversing it is a SQL ticket. Confirm dialog spells out the
    // block id + the slab / remainder counts so the auditor reads
    // before clicking yes.
    const slabs = row.payloadSummary?.cutCount ?? 0;
    const remainders = row.payloadSummary?.remainderCount ?? 0;
    const extras = row.payloadSummary?.extraCount ?? 0;
    const transfers = row.payloadSummary?.transferCount ?? 0;
    const lines = [
      `Approve cut for block ${row.blockId}?`,
      "",
      `This will commit:`,
      `  • ${slabs} slab(s) marked CUT`,
      ...(extras > 0 ? [`  • ${extras} extra slab(s)`] : []),
      ...(transfers > 0 ? [`  • ${transfers} transferred slab(s)`] : []),
      `  • ${remainders} remainder piece(s) → new restocked block(s)`,
      "",
      "Reversing an approval requires a developer SQL fix.",
      "",
      "Tap OK ONLY if every slab + remainder above matches what was actually cut.",
    ];
    if (!window.confirm(lines.join("\n"))) return;
    setActionError(null);
    startTransition(async () => {
      const fd = new FormData();
      fd.set("session_block_id", row.id);
      const result = await approveAction(fd);
      if (!result.ok) {
        setActionError(result.error);
        return;
      }
      router.refresh();
    });
  }

  function runUnlock() {
    setActionError(null);
    startTransition(async () => {
      const fd = new FormData();
      fd.set("session_block_id", row.id);
      fd.set("note", unlockNote.trim());
      const result = await unlockAction(fd);
      if (!result.ok) {
        setActionError(result.error);
        return;
      }
      setShowUnlock(false);
      setUnlockNote("");
      router.refresh();
    });
  }

  function runLock() {
    setActionError(null);
    startTransition(async () => {
      const fd = new FormData();
      fd.set("session_block_id", row.id);
      const result = await lockAction(fd);
      if (!result.ok) {
        setActionError(result.error);
        return;
      }
      router.refresh();
    });
  }

  const hasPrecut = (row.precutCount ?? 0) > 0;
  return (
    <div
      className="plan-card"
      style={
        unlocked
          ? { borderLeft: "5px solid #16a34a", background: "rgba(34, 197, 94, 0.05)" }
          : hasPrecut
            // Mig 126 — amber card: this block released pre-cut slabs early
            // (some may already be carving); the auditor should know the
            // history before approving.
            ? { borderLeft: "5px solid #d97706", background: "rgba(217, 119, 6, 0.06)" }
            : { borderLeft: "5px solid var(--gold-dark)" }
      }
    >
      <div className="record-head" style={{ flexWrap: "wrap", gap: 10, alignItems: "flex-start" }}>
        <div style={{ flex: 1, minWidth: 0 }}>
          <strong style={{ fontFamily: "ui-monospace, monospace", fontSize: 15 }}>
            {row.blockId}
          </strong>
          {hasPrecut && (
            <span
              className="role-pill"
              title="Some slabs of this block were released early (pre-cut) and may already be in carving — they were locked-in on the cutter's submission."
              style={{ marginLeft: 8, fontSize: 10, fontWeight: 800, background: "rgba(217,119,6,0.15)", color: "#92400e", border: "1px solid rgba(217,119,6,0.45)", verticalAlign: "middle" }}
            >
              ⏳ PRE-CUT · {row.precutCount} released early
            </span>
          )}
          <p className="muted" style={{ margin: "2px 0 0", fontSize: 12 }}>
            {row.sessionCode ?? "—"}
            {row.stone ? ` · ${row.stone}` : ""}
            {typeof row.yard === "number" ? ` · Yard ${row.yard}` : ""}
          </p>
          <p style={{ margin: "4px 0 0", fontSize: 11, color: "var(--muted)" }}>
            Submitted{" "}
            {row.submittedAt
              ? new Date(row.submittedAt).toLocaleString("en-IN", { timeZone: "Asia/Kolkata",
                  day: "numeric",
                  month: "short",
                  hour: "2-digit",
                  minute: "2-digit",
                })
              : "—"}
            {row.submittedByName && (
              <>
                {" "}by{" "}
                <span style={{ color: "var(--gold-dark)", fontWeight: 600 }}>
                  {row.submittedByName}
                </span>
              </>
            )}
            {row.operatorName && (
              <>
                {" · "}
                👷{" "}
                <span style={{ color: "#15803d", fontWeight: 600 }}>
                  {row.operatorName}
                </span>
              </>
            )}
          </p>
          {row.editedAt && (
            <p style={{ margin: "2px 0 0", fontSize: 11, color: "var(--muted)" }}>
              Last edited{" "}
              {new Date(row.editedAt).toLocaleString("en-IN", { timeZone: "Asia/Kolkata",
                day: "numeric",
                month: "short",
                hour: "2-digit",
                minute: "2-digit",
              })}
              {row.editedByName ? ` by ${row.editedByName}` : ""}
            </p>
          )}
        </div>

        <div style={{ display: "flex", flexDirection: "column", alignItems: "flex-end", gap: 6 }}>
          <span
            className="role-pill"
            style={{
              background: "var(--gold)",
              color: "#fff",
              fontWeight: 700,
              fontSize: 11,
            }}
          >
            👀 Awaiting audit
          </span>
          {unlocked && (
            <span
              style={{
                fontSize: 10,
                fontWeight: 700,
                padding: "2px 8px",
                borderRadius: 999,
                background: "rgba(34, 197, 94, 0.14)",
                color: "#15803d",
                letterSpacing: "0.05em",
                textTransform: "uppercase",
              }}
              title={
                row.unlockNote
                  ? `Cutter can edit · note: ${row.unlockNote}`
                  : "Cutter can edit this block"
              }
            >
              🔓 Cutter unlocked
            </span>
          )}
          <Link
            href={`/cutting/${row.id}`}
            style={{
              textDecoration: "none",
              fontSize: 12,
              padding: "4px 12px",
              background: "var(--bg)",
              border: "1px solid var(--border)",
              borderRadius: 6,
              color: "var(--text)",
              fontWeight: 500,
              whiteSpace: "nowrap",
            }}
          >
            View →
          </Link>
        </div>
      </div>

      {summary && (
        <div
          className="chip-row"
          style={{
            marginTop: 10,
            display: "flex",
            gap: 8,
            flexWrap: "wrap",
            alignItems: "center",
          }}
        >
          <SummaryChip label="cut" count={summary.cutCount} color="#15803d" />
          {summary.notCutCount > 0 && (
            <SummaryChip label="not cut" count={summary.notCutCount} color="#b91c1c" />
          )}
          {summary.extraCount > 0 && (
            <SummaryChip label="from inventory" count={summary.extraCount} color="#b45309" />
          )}
          {summary.transferCount > 0 && (
            <SummaryChip
              label="transferred"
              count={summary.transferCount}
              color="#7c3aed"
            />
          )}
          {summary.remainderCount > 0 && (
            <SummaryChip
              label="remainder pcs"
              count={summary.remainderCount}
              color="#0f766e"
            />
          )}
          <span style={{ fontSize: 11, color: "var(--muted)" }}>
            📍{" "}
            <span style={{ color: "var(--text)", fontWeight: 600 }}>
              {summary.stockLocation ?? "—"}
            </span>
          </span>
          {summary.restock && (
            <span
              style={{
                fontSize: 10,
                fontWeight: 700,
                color: "#0f766e",
                background: "rgba(15,118,110,0.12)",
                padding: "2px 8px",
                borderRadius: 4,
                textTransform: "uppercase",
                letterSpacing: "0.05em",
              }}
            >
              ♻ Restock
            </span>
          )}
        </div>
      )}

      {/* Projected recovery bar — same green / yellow / red breakdown the
          cutting card shows, but computed from the submitted payload so
          the auditor sees efficiency BEFORE approving. */}
      {row.recovery && (
        <div style={{ marginTop: 10 }}>
          <div style={{ display: "flex", justifyContent: "space-between", fontSize: 11, marginBottom: 4 }}>
            <span className="muted">Projected recovery</span>
            <span style={{ fontWeight: 700, color: "var(--gold-dark)" }}>
              {row.recovery.slabPct + row.recovery.restockPct}% recovered
            </span>
          </div>
          <div
            title={`Slabs ${row.recovery.slabPct}% · Restockable ${row.recovery.restockPct}% · Waste ${row.recovery.wastePct}%`}
            style={{ display: "flex", height: 8, borderRadius: 999, overflow: "hidden", background: "var(--surface-alt, #e5e7eb)" }}
          >
            <span style={{ width: `${row.recovery.slabPct}%`, background: "#15803d" }} />
            <span style={{ width: `${row.recovery.restockPct}%`, background: "#eab308" }} />
            <span style={{ width: `${row.recovery.wastePct}%`, background: "#b91c1c" }} />
          </div>
          <div style={{ display: "flex", gap: 14, fontSize: 10.5, marginTop: 4 }}>
            <span><strong style={{ color: "#15803d" }}>{row.recovery.slabPct}%</strong> slab</span>
            {row.recovery.restockPct > 0 && (
              <span><strong style={{ color: "#a16207" }}>{row.recovery.restockPct}%</strong> restock</span>
            )}
            <span><strong style={{ color: "#b91c1c" }}>{row.recovery.wastePct}%</strong> waste</span>
          </div>
        </div>
      )}

      {/* Sent-back / unlock note — prominently shown when present and
          the block is currently unlocked. Auditor sees this for context;
          cutter sees this as the "what to fix" reminder. */}
      {unlocked && row.unlockNote && (
        <div
          style={{
            marginTop: 10,
            padding: "10px 12px",
            background: "rgba(34, 197, 94, 0.10)",
            border: "1px solid rgba(22, 163, 74, 0.35)",
            borderRadius: 6,
          }}
        >
          <div
            style={{
              fontSize: 10,
              fontWeight: 700,
              color: "#15803d",
              textTransform: "uppercase",
              letterSpacing: "0.06em",
              marginBottom: 4,
            }}
          >
            🔓 Auditor note · cutter can edit
            {row.unlockByName ? ` · from ${row.unlockByName}` : ""}
          </div>
          <p style={{ margin: 0, fontSize: 13, color: "var(--text)", lineHeight: 1.5 }}>
            {row.unlockNote}
          </p>
        </div>
      )}

      {actionError && (
        <div
          role="alert"
          style={{
            marginTop: 10,
            padding: "10px 12px",
            background: "rgba(220,38,38,0.08)",
            border: "1.5px solid #dc2626",
            borderRadius: 6,
            color: "#7f1d1d",
            fontSize: 12,
          }}
        >
          <strong>Action failed:</strong> {actionError}
        </div>
      )}

      <div
        className="record-actions"
        style={{ marginTop: 12, gap: 8, display: "flex", flexWrap: "wrap" }}
      >
        {/* Auditor — full action set */}
        {canApprove && (
          <>
            <button
              type="button"
              className="primary-button"
              onClick={runApprove}
              disabled={pending}
              style={{ fontSize: 13 }}
            >
              {pending ? "Approving…" : "✓ Approve"}
            </button>
            <Link
              href={`/cutting/${row.id}?edit=approval`}
              style={{
                textDecoration: "none",
                fontSize: 13,
                padding: "8px 16px",
                background: "var(--bg)",
                border: "1px solid var(--border)",
                borderRadius: 6,
                color: "var(--text)",
                fontWeight: 600,
                whiteSpace: "nowrap",
              }}
            >
              ✏ Edit
            </Link>
            {unlocked ? (
              <button
                type="button"
                onClick={runLock}
                disabled={pending}
                style={{
                  fontSize: 13,
                  padding: "8px 16px",
                  background: "var(--bg)",
                  border: "1px solid var(--border)",
                  borderRadius: 6,
                  color: "#b45309",
                  fontWeight: 600,
                  cursor: pending ? "wait" : "pointer",
                }}
                title="Revoke cutter's edit permission. Cutter goes back to read-only."
              >
                🔒 Lock cutter edit
              </button>
            ) : (
              <button
                type="button"
                onClick={() => setShowUnlock((v) => !v)}
                disabled={pending}
                style={{
                  fontSize: 13,
                  padding: "8px 16px",
                  background: showUnlock ? "rgba(22, 163, 74, 0.14)" : "var(--bg)",
                  border: "1px solid var(--border)",
                  borderRadius: 6,
                  color: "#15803d",
                  fontWeight: 600,
                  cursor: pending ? "wait" : "pointer",
                }}
                title="Allow the cutter to edit this block. Status stays awaiting_approval."
              >
                🔓 Allow cutter to edit
              </button>
            )}
          </>
        )}

        {/* Cutter — view-only or edit (when unlocked) */}
        {cutterCanEdit && (
          <Link
            href={`/cutting/${row.id}?edit=approval`}
            className="primary-button"
            style={{
              textDecoration: "none",
              fontSize: 13,
              padding: "8px 16px",
              fontWeight: 700,
              whiteSpace: "nowrap",
            }}
          >
            ✏ Edit submission
          </Link>
        )}
        {!canApprove && !cutterCanEdit && row.isOwnSubmission && (
          <span
            className="muted"
            style={{
              fontSize: 12,
              padding: "6px 12px",
              border: "1px dashed var(--border)",
              borderRadius: 6,
            }}
          >
            Waiting for auditor review. You'll get an Edit button if
            they unlock the row for you.
          </span>
        )}
      </div>

      {showUnlock && canApprove && !unlocked && (
        <div
          style={{
            marginTop: 12,
            padding: 12,
            background: "var(--bg)",
            border: "1px solid var(--border)",
            borderRadius: 6,
          }}
        >
          <label
            style={{
              fontSize: 11,
              fontWeight: 700,
              color: "var(--muted)",
              textTransform: "uppercase",
              letterSpacing: "0.05em",
            }}
          >
            Note for the cutter (optional)
          </label>
          <textarea
            value={unlockNote}
            onChange={(e) => setUnlockNote(e.target.value)}

            rows={3}
            style={{
              width: "100%",
              marginTop: 6,
              padding: "8px 10px",
              fontSize: 13,
              border: "1px solid var(--border)",
              borderRadius: 4,
              background: "var(--surface)",
              color: "var(--text)",
              resize: "vertical",
            }}
          />
          <div style={{ display: "flex", gap: 8, marginTop: 10, flexWrap: "wrap" }}>
            <button
              type="button"
              onClick={runUnlock}
              disabled={pending}
              className="primary-button"
              style={{ fontSize: 13, background: "#16a34a" }}
            >
              {pending ? "Unlocking…" : "🔓 Allow cutter to edit"}
            </button>
            <button
              type="button"
              onClick={() => {
                setShowUnlock(false);
                setUnlockNote("");
              }}
              disabled={pending}
              style={{
                fontSize: 13,
                padding: "8px 16px",
                background: "transparent",
                border: "1px solid var(--border)",
                borderRadius: 6,
                color: "var(--muted)",
                fontWeight: 500,
                cursor: pending ? "wait" : "pointer",
              }}
            >
              Cancel
            </button>
          </div>
        </div>
      )}
    </div>
  );
}

function SummaryChip({
  label,
  count,
  color,
}: {
  label: string;
  count: number;
  color: string;
}) {
  return (
    <span
      style={{
        display: "inline-flex",
        alignItems: "center",
        gap: 4,
        fontSize: 11,
        padding: "3px 9px",
        background: `${color}1F`,
        border: `1px solid ${color}44`,
        borderRadius: 4,
        color: "var(--text)",
        fontWeight: 600,
      }}
    >
      <strong style={{ color, fontFamily: "ui-monospace, monospace" }}>
        {count}
      </strong>
      <span style={{ color: "var(--muted)", fontWeight: 500 }}>{label}</span>
    </span>
  );
}
